// Runs even when MongoDB returned 0 items (new user / no history)
// Handles both regular messages and inline keyboard callback_query taps
const trigger = $('Telegram Trigger').first().json;
const history = $input.all()
  .map(i => i.json)
  .filter(d => d.role && d.content)
  .reverse();

let chatId, userText, callbackQueryId;
if (trigger.callback_query) {
  // Inline keyboard button was tapped
  chatId = trigger.callback_query.message.chat.id;
  userText = trigger.callback_query.data; // the callback_data we set = question text
  callbackQueryId = trigger.callback_query.id;
} else {
  // Regular text message
  chatId = trigger.message.chat.id;
  userText = trigger.message.text || '';
  callbackQueryId = null;
}

return [{
  json: {
    chatId,
    userText,
    callbackQueryId,
    history
  }
}];

// Build prompt from collected history + current user message
const { chatId, userText, history } = $input.first().json;

const historyText = history.length > 0
  ? history.map(d => `${d.role === 'user' ? 'User' : 'Assistant'}: ${d.content}`).join('\n')
  : '';

// Keyword-based intent detection
const metricKeywords = [
  'cpu', 'memory', 'ram', 'disk', 'up', 'down', 'health', 'status',
  'monitor', 'metric', 'load', 'usage', 'target', 'node', 'k8s',
  'kubernetes', 'database', 'postgres', 'redis', 'docker', 'alert',
  'prometheus', 'grafana', 'vm', 'server'
];
const lower = userText.toLowerCase();
const needsMetrics = metricKeywords.some(k => lower.includes(k));

const systemPrompt = `You are a homelab infrastructure assistant for a server running Proxmox with several VMs:
- K8s nodes: 192.168.100.201-203
- Database VM (Postgres, MongoDB, Redis): 192.168.100.205
- Monitoring VM (Prometheus + Grafana): 192.168.100.220
- CI/CD VM: 192.168.100.240
- n8n VM: 192.168.100.230

Answer clearly and concisely. If given Prometheus data, interpret it in plain language in telegram friendly format!`;

const fullPrompt = [
  systemPrompt,
  historyText ? '\nConversation so far:\n' + historyText : '',
  `\nUser: ${userText}\nAssistant:`
].filter(Boolean).join('\n');

return [{
  json: {
    chatId,
    userText,
    needsMetrics,
    fullPrompt
  }
}];

// Parse the initial Ollama response
const ollamaResp = $input.first().json;
const promptCtx  = $('Build Prompt').first().json;
const rawAnswer  = (ollamaResp.response || '').trim();

// Detect which Prometheus query to run based on keyword intent
const lower = promptCtx.userText.toLowerCase();

let promqlQuery = null;
if (promptCtx.needsMetrics) {
  if (lower.includes('cpu')) {
    promqlQuery = '100 - (avg by(instance) (rate(node_cpu_seconds_total{mode="idle"}[5m])) * 100)';
  } else if (lower.includes('memory') || lower.includes('ram')) {
    promqlQuery = '(1 - (node_memory_MemAvailable_bytes / node_memory_MemTotal_bytes)) * 100';
  } else if (lower.includes('disk')) {
    promqlQuery = '(node_filesystem_size_bytes{mountpoint="/"} - node_filesystem_free_bytes{mountpoint="/"}) / node_filesystem_size_bytes{mountpoint="/"} * 100';
  } else if (lower.includes('up') || lower.includes('down') || lower.includes('status') || lower.includes('health') || lower.includes('target')) {
    promqlQuery = 'up';
  } else {
    // Generic: just check all targets up status
    promqlQuery = 'up';
  }
}

return [{
  json: {
    chatId: promptCtx.chatId,
    userText: promptCtx.userText,
    fullPrompt: promptCtx.fullPrompt,
    needsMetrics: promptCtx.needsMetrics,
    initialAnswer: rawAnswer,
    promqlQuery
  }
}];

// Format Prometheus results into a readable summary for the LLM
const promData = $input.first().json;
const ctx = $('Parse Intent').first().json;

const results = (promData.data && promData.data.result) || [];

let summary = '';
if (results.length === 0) {
  summary = 'No data returned from Prometheus.';
} else {
  summary = results.map(r => {
    const labels = Object.entries(r.metric || {})
      .filter(([k]) => k !== '__name__')
      .map(([k, v]) => `${k}=${v}`)
      .join(', ');
    const value = parseFloat(r.value[1]).toFixed(2);
    return `${labels || 'instance'}: ${value}`;
  }).join('\n');
}

// Second prompt: ask LLM to interpret the metrics
const interpretPrompt = `${ctx.fullPrompt}

Real-time Prometheus data for query (${ctx.promqlQuery}):
${summary}

Based on the above data, answer the user's question: "${ctx.userText}"
Be concise. Highlight any values that look abnormal (CPU>80%, memory>85%, disk>80%, status=0).\nAssistant:`;

return [{
  json: {
    chatId: ctx.chatId,
    userText: ctx.userText,
    interpretPrompt,
    metricsSummary: summary
  }
}];

// Merge both branches into a single { chatId, userText, finalAnswer } object
const items = $input.all();

// From the metrics branch (Ask Ollama interpret)
const ollamaResp = items[0].json;
const formatCtx  = $('Format Metrics').first().json;

return [{
  json: {
    chatId: formatCtx.chatId,
    userText: formatCtx.userText,
    finalAnswer: (ollamaResp.response || '').trim()
  }
}];

// Pass-through for the no-metrics branch
const ctx = $input.first().json;
return [{
  json: {
    chatId: ctx.chatId,
    userText: ctx.userText,
    finalAnswer: ctx.initialAnswer
  }
}];

const item = $input.first().json;

// Prepare two documents to save: user message + assistant reply
return [
  {
    json: {
      chat_id: item.chatId,
      role: 'user',
      content: item.userText,
      ts: Date.now()
    }
  },
  {
    json: {
      chat_id: item.chatId,
      role: 'assistant',
      content: item.finalAnswer,
      ts: Date.now() + 1
    }
  }
];

const item = $input.first().json;
let text = (item.finalAnswer || '(no response)');
// Replace curly braces from PromQL/JSON
text = text.replace(/\{/g, '(').replace(/\}/g, ')');
// Remove backslashes
text = text.replace(/\\/g, '');
// Replace backticks (Telegram code markers)
text = text.replace(/`/g, "'");
// Remove * and _ — Telegram Markdown treats these as bold/italic markers
text = text.replace(/\*/g, '').replace(/_/g, ' ');
// Replace [ ] — Telegram treats these as link markers
text = text.replace(/\[/g, '(').replace(/\]/g, ')');
// Trim to Telegram's 4096 char limit
text = text.slice(0, 4096);
return [{ json: { ...item, finalAnswer: text } }];
